SELECT module_name, performance_metrics
FROM collection_usage
WHERE usage_id = 1 AND last_updated = '2022-03-01';

SELECT DISTINCT class_name
FROM collections
WHERE blocking = 0;

SELECT characteristic_name, description
FROM collection_characteristics
WHERE collection_id = 1;

SELECT class_name, interfaces, elements, sorted, blocking, thread_safety, concurrent_access, performance_implications, use_cases, size_limit, version
FROM collections
WHERE thread_safety = 1 AND concurrent_access = 1;

SELECT module_name 
FROM collection_usage 
WHERE description LIKE '%Processing%';
